function BrandMark() { return <div className="brand"><span className="brand-mark"><Sparkles size={18} aria-hidden="true" /></span><span>Family Harmony</span></div> }

function getErrorMessage(error, fallback) {
  const message = error?.message || ''
  if (/invalid login credentials/i.test(message)) return 'That email and password do not match an approved account.'
  if (/email not confirmed/i.test(message)) return 'This account needs to be confirmed by the household owner.'
  return message || fallback
}

function ConnectionRequired() {
  return <div className="auth-screen"><section className="auth-card centered-card"><BrandMark /><span className="auth-icon"><LockKeyhole size={25} /></span><p className="eyebrow">Private access</p><h1>Family Harmony is waiting for its secure connection.</h1><p>Add the Supabase URL and anon key to this environment, then redeploy. This app never shows a public sign-up route.</p></section></div>
}

function SignInPage() {
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [showPassword, setShowPassword] = useState(false)
  const [error, setError] = useState('')
  const [submitting, setSubmitting] = useState(false)
  async function handleSubmit(event) {
    event.preventDefault(); setError(''); setSubmitting(true)
    const { error: signInError } = await supabase.auth.signInWithPassword({ email: email.trim(), password })
    setSubmitting(false)
    if (signInError) setError(getErrorMessage(signInError, 'We could not sign you in.'))
  }
  return <div className="auth-screen auth-split"><section className="auth-story"><BrandMark /><div><p className="eyebrow">A home, held together</p><h1>Good things grow when we notice them.</h1><p>A private, calm place for your household&apos;s everyday care and tiny wins.</p></div><div className="auth-house" aria-hidden="true"><span /><i /><i /><i /></div></section><section className="auth-panel"><div className="auth-card"><span className="auth-icon"><LockKeyhole size={25} /></span><p className="eyebrow">Private household access</p><h1>Welcome back.</h1><p className="form-intro">Use the email and password your household owner set up for you.</p><form onSubmit={handleSubmit}><label htmlFor="email">Email address</label><input id="email" type="email" autoComplete="email" placeholder="you@example.com" value={email} onChange={(event) => setEmail(event.target.value)} required disabled={submitting} /><label htmlFor="password">Password</label><div className="password-control"><input id="password" type={showPassword ? 'text' : 'password'} autoComplete="current-password" value={password} onChange={(event) => setPassword(event.target.value)} required disabled={submitting} /><button type="button" aria-label={showPassword ? 'Hide password' : 'Show password'} onClick={() => setShowPassword((current) => !current)}>{showPassword ? <EyeOff size={18} /> : <Eye size={18} />}</button></div>{error && <p className="form-error" role="alert">{error}</p>}<button className="primary-button form-button" type="submit" disabled={submitting}>{submitting ? 'Signing in...' : 'Sign in'} <ChevronRight size={18} aria-hidden="true" /></button></form><p className="form-note">No public sign-up. Need access? Ask your household owner to create an account for you.</p></div></section></div>
}

function HouseholdSetup({ user, onWorkspaceChanged }) {
  const [name, setName] = useState('')
  const [error, setError] = useState('')
  const [submitting, setSubmitting] = useState(false)
  async function handleCreate(event) {
    event.preventDefault(); setError(''); setSubmitting(true)
    try { await createHousehold(name, user.id); await onWorkspaceChanged() } catch (createError) { setError(getErrorMessage(createError, 'We could not create this household.')) } finally { setSubmitting(false) }
  }
  return <div className="auth-screen"><section className="auth-card setup-card"><BrandMark /><span className="auth-icon"><ShieldCheck size={25} /></span><p className="eyebrow">Private by design</p><h1>You&apos;re signed in, but this account has no household access yet.</h1><p className="form-intro">If you&apos;re starting the family space, create it below. Otherwise, ask the owner to add this exact email in Settings.</p><form onSubmit={handleCreate}><label htmlFor="household-name">Household name</label><input id="household-name" value={name} onChange={(event) => setName(event.target.value)} placeholder="For example, The Linden home" required minLength="2" disabled={submitting} />{error && <p className="form-error" role="alert">{error}</p>}<button className="primary-button form-button" type="submit" disabled={submitting}>{submitting ? 'Creating...' : 'Create my household'} <ChevronRight size={18} aria-hidden="true" /></button></form><button className="muted-button" onClick={onWorkspaceChanged} disabled={submitting}>Check my access again</button><button className="text-button sign-out-text" onClick={() => supabase.auth.signOut()}>Sign out <LogOut size={16} aria-hidden="true" /></button></section></div>
}

function AppShell({ children, household, profile, user }) {
  const location = useLocation()
  const language = profile?.locale || 'en'
  const today = new Intl.DateTimeFormat(language === 'ru' ? 'ru-RU' : 'en-US', { weekday: 'long', month: 'long', day: 'numeric' }).format(new Date())
  const displayName = profile?.display_name || user.email?.split('@')[0] || 'there'
  const firstName = displayName.split(' ')[0]
  const initial = displayName.charAt(0).toUpperCase()
  const text = language === 'ru' ? { skip: 'К содержанию', settings: 'Настройки', morning: 'Доброе утро', private: 'Личное пространство', nav: 'Основная навигация' } : { skip: 'Skip to content', settings: 'Settings', morning: 'Good morning', private: 'Private space', nav: 'Primary navigation' }
  return <div className="app-shell"><a className="skip-link" href="#main-content">{text.skip}</a><aside className="sidebar"><BrandMark /><nav className="side-nav" aria-label={text.nav}>{navItems.map(({ to, label, icon: Icon }) => <NavLink key={to} to={to} className={({ isActive }) => `nav-link ${isActive ? 'active' : ''}`}><Icon size={19} aria-hidden="true" /><span>{label[language]}</span></NavLink>)}</nav><div className="sidebar-footer"><NavLink to="/settings" className={({ isActive }) => `nav-link ${isActive ? 'active' : ''}`}><Settings size={19} aria-hidden="true" /><span>{text.settings}</span></NavLink><p><span className="presence-dot" />{household.name}</p></div></aside><div className="app-frame"><header className="topbar"><div><p className="eyebrow">{today}</p><p className="welcome-line">{text.morning}, {firstName}</p></div><div className="topbar-actions"><span className="connection-status connected"><span />{text.private}</span><button className="icon-button" aria-label="Notifications"><Bell size={20} /></button><NavLink className="avatar" to="/settings" aria-label="Open settings">{initial}</NavLink></div></header><main id="main-content" key={location.pathname} className="main-content">{children}</main></div><nav className="mobile-nav" aria-label={text.nav}>{navItems.map(({ to, label, icon: Icon }) => <NavLink key={to} to={to} className={({ isActive }) => `mobile-nav-link ${isActive ? 'active' : ''}`}><Icon size={20} aria-hidden="true" /><span>{label[language]}</span></NavLink>)}</nav></div>
}

function DashboardPage({ checkIns, household, familyGoal, onToggleCheckIn, actionError }) {
  const navigate = useNavigate()
  const completed = Object.values(checkIns).filter(Boolean).length
  const progress = Math.round((completed / checkInItems.length) * 100)
  const goalPercent = familyGoal ? Math.min(100, Math.round((familyGoal.progress / familyGoal.target) * 100)) : 0
  return <><motion.section className="page-intro" {...fadeUp}><div><p className="eyebrow">{household.name}</p><h1>A little care goes a long way.</h1><p className="lead">Your home is already in motion. Pick one small thing and keep the warmth going.</p></div><button className="primary-button" onClick={() => navigate('/me')}><Plus size={18} aria-hidden="true" />Check in</button></motion.section>{actionError && <p className="form-error page-message" role="alert">{actionError}</p>}<section className="dashboard-grid" aria-label="Household dashboard"><motion.article className="card house-card" {...fadeUp} transition={{ ...fadeUp.transition, delay: 0.06 }}><div className="card-heading"><div><p className="eyebrow">This week at home</p><h2>Your hearth is glowing</h2></div><span className="glow-icon"><House size={21} aria-hidden="true" /></span></div><div className="house-illustration" aria-label="Illustration of a warm home with a glowing window"><span className="moon" /><span className="house-roof" /><span className="house-body"><i /><i /><i /></span><span className="tree tree-one" /><span className="tree tree-two" /></div><div className="house-progress"><div><span>Family glow</span><strong>{62 + completed * 8}%</strong></div><div className="progress-track"><span style={{ width: `${62 + completed * 8}%` }} /></div><p>One more shared moment unlocks the garden lights.</p></div></motion.article><motion.article className="card focus-card" {...fadeUp} transition={{ ...fadeUp.transition, delay: 0.12 }}><div className="card-heading"><div><p className="eyebrow">Family focus</p><h2>{familyGoal ? familyGoal.title : 'Choose a shared goal'}</h2></div>{familyGoal ? <UsersRound className="heading-icon" size={22} aria-hidden="true" /> : <Target className="heading-icon" size={22} aria-hidden="true" />}</div><p>{familyGoal ? familyGoal.description || `A gentle shared target for this week: ${familyGoal.target} small wins.` : 'Start one small, shared intention for the week ahead.'}</p>{familyGoal && <div className="focus-progress"><strong>{Math.min(familyGoal.progress, familyGoal.target)} of {familyGoal.target}</strong><div className="progress-track"><span style={{ width: `${goalPercent}%` }} /></div></div>}<button className="quiet-button" onClick={() => navigate('/challenges')}>{familyGoal ? 'See family goal' : 'Create a family goal'} <ChevronRight size={16} aria-hidden="true" /></button></motion.article><motion.article className="card meal-card" {...fadeUp} transition={{ ...fadeUp.transition, delay: 0.18 }}><p className="eyebrow">Next up</p><div className="meal-title"><span className="meal-icon"><Utensils size={20} aria-hidden="true" /></span><div><h2>Sunday dinner</h2><p>Pick a family favorite</p></div></div><div className="meal-options"><span>Roast veggie pasta</span><span>Taco night</span></div><button className="text-button" onClick={() => navigate('/meals')}>Cast your vote <ChevronRight size={16} aria-hidden="true" /></button></motion.article></section><motion.section className="section-block" {...fadeUp} transition={{ ...fadeUp.transition, delay: 0.22 }}><div className="section-heading"><div><p className="eyebrow">Today, together</p><h2>Small check-ins, real momentum</h2></div><span className="count-pill">{completed} / {checkInItems.length} complete</span></div><div className="checkin-grid">{checkInItems.map(({ id, label, note, icon: Icon, tint }) => { const done = checkIns[id]; return <button key={id} className={`checkin-card ${tint} ${done ? 'done' : ''}`} onClick={() => onToggleCheckIn(id)} aria-pressed={done}><span className="checkin-icon">{done ? <Check size={20} aria-hidden="true" /> : <Icon size={20} aria-hidden="true" />}</span><span className="checkin-copy"><strong>{label}</strong><small>{done ? 'Lovely - you did it.' : note}</small></span><span className="check-state">{done ? 'Done' : 'Mark done'}</span></button> })}</div><div className="daily-progress" aria-label={`${progress}% of daily check-ins complete`}><span style={{ width: `${progress}%` }} /></div></motion.section><motion.section className="activity-section" {...fadeUp} transition={{ ...fadeUp.transition, delay: 0.28 }}><div className="section-heading"><div><p className="eyebrow">Around the hearth</p><h2>Little wins from your people</h2></div><button className="text-button">View all <ChevronRight size={16} aria-hidden="true" /></button></div><div className="activity-list"><Activity initials="J" accent="lavender" text="Jade added a calm moment to her day" time="12 min ago" /><Activity initials="M" accent="peach" text="Mila voted for taco night" time="38 min ago" /><Activity initials="N" accent="mint" text="You kept a 5-day reading streak" time="Yesterday" /></div></motion.section></>
}

